mapper.select:
select
    id,
    tenant_id,
    file_id,
    operation_type,
    operation_result,
    operator_type,
    operator_id,
    trace_id,
    evidence_ref,
    detail_summary,
    created_at
from batch.file_audit_log
where tenant_id = #{tenantId}

    and id < #{cursorId}


    and operation_type = #{operationType}


    and operation_result = #{operationResult}


    and operator_id like concat('%', #{operatorId}, '%')


    and file_id = #{fileId}


    and trace_id like concat('%', #{traceId}, '%')


    and created_at >= #{fromTime}


    and created_at <= #{toTime}

order by id desc


        limit #{pageRequest.pageSize}

select count(1)
from batch.file_audit_log
where tenant_id = #{tenantId}

    and operation_type = #{operationType}


    and operation_result = #{operationResult}


    and operator_id like concat('%', #{operatorId}, '%')


    and file_id = #{fileId}


    and trace_id like concat('%', #{traceId}, '%')


    and created_at >= #{fromTime}


    and created_at <= #{toTime}
